index.ts
---

export type DocWidth = "narrow" | "normal" | "wide";
export type DocMargin = "tight" | "normal" | "roomy";

export interface LayoutSettings {
  width: DocWidth;
  margin: DocMargin;
  /** Show brief title / author / date in the running header (print + reading view). */
  runningHeader: boolean;
  /** Show page numbers in the footer of printed/exported output. */
  pageNumbers: boolean;
}

export const DEFAULT_LAYOUT: LayoutSettings = {
  width: "normal",
  margin: "normal",
  runningHeader: false,
  pageNumbers: true,
};

export interface Comment {
  id: string;
  text: string;
  selectedText: string;
  from: number;
  to: number;
  author: string;
  timestamp: number;
  resolved: boolean;
  replies: CommentReply[];
}

export interface CommentReply {
  id: string;
  text: string;
  author: string;
  timestamp: number;
}

export type PersonaReplyAuthor = "user" | "persona";

