content.content:
body {
  font-family: var(--font-sans);
  color: var(--color-ink);
  background-color: var(--color-paper);
  /* Subtle paper grain — barely-there noise to give the surface tooth */
  background-image:
    radial-gradient(
      circle at 25% 35%,
      rgba(31, 27, 22, 0.025) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 75% 65%,
      rgba(31, 27, 22, 0.02) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 45% 85%,
      rgba(31, 27, 22, 0.015) 0,
      transparent 1px
    );
  background-size:
    7px 7px,
    11px 11px,
    13px 13px;
  font-feature-settings:
    "kern",
    "liga",
    "onum" 1;
}

