 * Faint vermilion rules marking where the live margins sit, the way Word
 * and Google Docs show the header/footer and side margins. They track the
 * same --doc-pad-* custom properties that drive the page padding, so moving
 * the layout sliders moves the guides. Painted as the page's own background
 * so they always sit behind the text without any z-index juggling. */
.page-canvas {
  --guide: rgba(193, 39, 45, 0.28);
  background-image:
    linear-gradient(var(--guide), var(--guide)),
    linear-gradient(var(--guide), var(--guide)),
    linear-gradient(var(--guide), var(--guide)),
    linear-gradient(var(--guide), var(--guide));
  background-repeat: no-repeat;
  background-size:
    1px 100%,
    1px 100%,
    100% 1px,
    100% 1px;
  background-position:
    left var(--doc-pad-x, 3rem) top 0,
    right var(--doc-pad-x, 3rem) top 0,
    left 0 top var(--doc-pad-y, 2.5rem),
    left 0 bottom var(--doc-pad-bottom, 4rem);
}

